import { useState, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';

export default function Products() {
  const { authAxios } = useAuth();
  const [products, setProducts] = useState([]);
  const [modal, setModal] = useState(false);
  const [editing, setEditing] = useState(null);
  const [form, setForm] = useState({ name: '', category: '', price: '', stock: '' });
  const [msg, setMsg] = useState('');

  const load = () => authAxios.get('/products').then(r => setProducts(r.data));
  useEffect(() => { load(); }, []);

  const openAdd = () => { setEditing(null); setForm({ name:'', category:'', price:'', stock:'' }); setModal(true); };
  const openEdit = (p) => { setEditing(p); setForm({ name:p.name, category:p.category||'', price:p.price, stock:p.stock }); setModal(true); };

  const save = async () => {
    const data = { ...form, price: parseFloat(form.price), stock: parseInt(form.stock) || 0 };
    if (editing) await authAxios.put(`/products/${editing.id}`, data);
    else await authAxios.post('/products', data);
    setModal(false); setMsg('✅ Saved!'); load();
    setTimeout(() => setMsg(''), 2000);
  };

  const del = async (id) => {
    if (!window.confirm('Delete?')) return;
    await authAxios.delete(`/products/${id}`);
    load();
  };

  return (
    <div>
      <div className="page-header">
        <h1 className="page-title">👗 Products</h1>
        <button className="btn btn-primary" onClick={openAdd}>+ Add Product</button>
      </div>
      {msg && <div className="alert alert-success">{msg}</div>}
      <div className="card">
        <table className="data-table">
          <thead><tr><th>#</th><th>Dress Name</th><th>Category</th><th>Price</th><th>Stock</th><th>Status</th><th>Actions</th></tr></thead>
          <tbody>
            {products.map((p, i) => (
              <tr key={p.id}>
                <td>{i+1}</td>
                <td><strong>{p.name}</strong></td>
                <td>{p.category || '-'}</td>
                <td>₹{p.price.toLocaleString()}</td>
                <td>{p.stock}</td>
                <td>
                  <span className={`badge ${p.stock > 5 ? 'badge-success' : p.stock > 0 ? 'badge-warning' : 'badge-danger'}`}>
                    {p.stock > 5 ? 'In Stock' : p.stock > 0 ? 'Low Stock' : 'Out of Stock'}
                  </span>
                </td>
                <td>
                  <button className="btn btn-secondary btn-sm" onClick={() => openEdit(p)}>✏️ Edit</button>
                  {' '}
                  <button className="btn btn-danger btn-sm" onClick={() => del(p.id)}>🗑️</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        {products.length === 0 && <p style={{textAlign:'center', padding:'32px', color:'#999'}}>Products இல்லை. Add பண்ணுங்க!</p>}
      </div>

      {modal && (
        <div className="modal-overlay">
          <div className="modal">
            <div className="modal-header">
              <h3 className="modal-title">{editing ? '✏️ Edit Product' : '+ Add Product'}</h3>
              <button className="modal-close" onClick={() => setModal(false)}>✕</button>
            </div>
            {['name','category'].map(f => (
              <div className="form-group" key={f}>
                <label>{f === 'name' ? 'Dress Name *' : 'Category'}</label>
                <input className="form-control" value={form[f]} onChange={e => setForm({...form, [f]: e.target.value})}
                  placeholder={f === 'name' ? 'e.g. Saree, Churidar...' : 'e.g. Saree, Kids...'} />
              </div>
            ))}
            <div style={{display:'grid', gridTemplateColumns:'1fr 1fr', gap:'16px'}}>
              <div className="form-group">
                <label>Price (₹) *</label>
                <input type="number" className="form-control" value={form.price} onChange={e => setForm({...form, price: e.target.value})} />
              </div>
              <div className="form-group">
                <label>Stock Qty</label>
                <input type="number" className="form-control" value={form.stock} onChange={e => setForm({...form, stock: e.target.value})} />
              </div>
            </div>
            <button className="btn btn-primary" style={{width:'100%'}} onClick={save}>💾 Save</button>
          </div>
        </div>
      )}
    </div>
  );
}
